class CyclicPartsRule(Rule):
    """Apply PartsRule multiple times to integrate exp(x)*sin(x)"""
    parts_rules: list[PartsRule]
    coefficient: Expr

# ╔══ CCTT ══════════════════════════════════════════════════╗
# ║ Path(eval(), eval produces the expected output) over Any   ║
